/* quiz-data-extra4.js — completamento a 50 per argomento (parte A: subnetting→ssl-tls) */
window.QUIZ_DATA_EXTRA4 = {

"subnetting":[
  {id:300,type:"mc",topic:"Calcolo",text:"Qual è il numero di host utilizzabili in una /31?",options:["0","2","1","4"],correct:0,explanation:"/31 → 2^1-2 = 0. Usata per link PPP (RFC 3021) dove si usano entrambi gli indirizzi senza sottrarre rete e broadcast, ma tecnicamente 0 host secondo la formula classica."},
  {id:301,type:"mc",topic:"CIDR",text:"Quanti indirizzi totali ha un blocco /19?",options:["512","1024","2048","8192"],correct:3,explanation:"/19 → 32-19=13 bit host → 2^13 = 8192 indirizzi totali."},
  {id:302,type:"mc",topic:"Calcolo",text:"Dato 172.20.100.50/22, qual è il broadcast?",options:["172.20.103.255","172.20.100.255","172.20.102.255","172.20.101.255"],correct:0,explanation:"/22: blocco di 4 nel terzo ottetto. 100/4=25 → inizio blocco 25×4=100. Range: 172.20.100.0–172.20.103.255. Broadcast: 172.20.103.255."},
  {id:303,type:"mc",topic:"Wildcard",text:"In OSPF, 'network 10.0.0.0 0.0.0.255 area 0' annuncia interfacce nel range:",options:["10.0.0.0–10.255.255.255","10.0.0.0–10.0.0.255","10.0.0.0–10.0.255.255","10.0.0.1–10.0.0.254"],correct:1,explanation:"Wildcard 0.0.0.255: primi 3 ottetti fissi (10.0.0), ultimo libero. Range: 10.0.0.0–10.0.0.255."},
  {id:304,type:"mc",topic:"Calcolo",text:"Una rete /16 viene suddivisa in /20. Quante sottoreti si ottengono?",options:["16","32","256","64"],correct:0,explanation:"Bit subnet aggiuntivi: 20-16=4. 2^4=16 sottoreti /20, ognuna con 2^12-2=4094 host."},
  {id:305,type:"mc",topic:"VLSM",text:"Ordinando per VLSM, quale sottorete si assegna PER PRIMA?",options:["La più piccola","La più grande","In ordine alfabetico","Quella con più router"],correct:1,explanation:"Con VLSM si parte sempre dalla sottorete con più host e si scende verso quella più piccola, per evitare sprechi e sovrapposizioni di indirizzi."},
  {id:306,type:"tf",topic:"Calcolo",text:"In una rete /24 il terzultimo host ha indirizzo xxx.xxx.xxx.253.",options:["Vero","Falso"],correct:1,explanation:"FALSO. L'ultimo host è .254 (broadcast .255), il penultimo è .253, il terzultimo è .252. Il terz'ultimo host di una /24 è .252, non .253."},
  {id:307,type:"mc",topic:"CIDR",text:"La notazione 'supernet' 192.168.0.0/22 copre quante reti /24?",options:["2","4","8","16"],correct:1,explanation:"22-24 = -2, quindi 2^2=4 reti /24: 192.168.0.0, 192.168.1.0, 192.168.2.0, 192.168.3.0."},
  {id:308,type:"mc",topic:"Calcolo",text:"Primo host di 10.5.8.0/21?",options:["10.5.8.0","10.5.8.1","10.5.9.1","10.5.0.1"],correct:1,explanation:"/21: rete 10.5.8.0. Primo host = rete+1 = 10.5.8.1. Broadcast = 10.5.15.255."},
  {id:309,type:"mc",topic:"Calcolo",text:"Quanti host ha una rete con subnet mask 255.255.252.0?",options:["1022","510","254","2046"],correct:0,explanation:"255.255.252.0 = /22 → 10 bit host → 2^10-2 = 1022 host."},
],

"nat-icmp":[
  {id:300,type:"mc",topic:"NAT",text:"Quale tipo di NAT usa una singola mappatura IP senza porte?",options:["PAT","NAT Dinamico","NAT Statico","DNAT"],correct:2,explanation:"NAT Statico: mappatura 1:1 fissa tra un IP privato e un IP pubblico. Non usa le porte per distinguere le sessioni — solo IP."},
  {id:301,type:"mc",topic:"ICMP",text:"Quale tool usa ICMP Echo Request/Reply per misurare la latenza?",options:["traceroute","nmap","ping","netstat"],correct:2,explanation:"ping invia ICMP Echo Request e misura il tempo fino all'ICMP Echo Reply (RTT - Round Trip Time)."},
  {id:302,type:"mc",topic:"NAT",text:"Il NAT 'inside global' address è:",options:["L'IP privato del client interno","L'IP pubblico con cui appare il client all'esterno","L'IP del gateway ISP","L'IP di un server nella DMZ"],correct:1,explanation:"Terminologia NAT Cisco: Inside Global = IP pubblico con cui gli host interni appaiono verso Internet. Inside Local = IP privato reale del client."},
  {id:303,type:"mc",topic:"ICMP",text:"Un TTL di 1 in un pacchetto significa che:",options:["Il pacchetto non scadrà mai","Il pacchetto verrà scartato dal primo router che lo riceve","Il pacchetto è già alla destinazione","Il pacchetto usa route speciale"],correct:1,explanation:"TTL=1: il primo router decrementa a 0 e scarta il pacchetto, inviando ICMP Time Exceeded al mittente. Usato da traceroute per scoprire il primo hop."},
  {id:304,type:"mc",topic:"NAT",text:"Cosa accade quando il pool NAT dinamico è esaurito?",options:["Viene usato PAT automaticamente","Nuove connessioni vengono rifiutate","Il router espande il pool","Il traffico va in broadcast"],correct:1,explanation:"Se tutti gli IP del pool NAT dinamico sono in uso, nuove richieste di connessione vengono rifiutate fino a che una sessione esistente non si libera."},
  {id:305,type:"mc",topic:"ICMP",text:"ICMP appartiene a quale livello del modello OSI?",options:["L2 Data Link","L3 Network","L4 Transport","L7 Application"],correct:1,explanation:"ICMP lavora a livello 3 (Network/IP). È incapsulato direttamente nell'header IP con protocollo numero 1."},
  {id:306,type:"tf",topic:"NAT",text:"Con NAT, i server HTTP interni possono ricevere connessioni in entrata dall'esterno senza configurazione aggiuntiva.",options:["Vero","Falso"],correct:1,explanation:"FALSO. Per ricevere connessioni in entrata serve il Port Forwarding (DNAT): mappare una porta pubblica verso l'IP:porta del server interno. Il NAT standard (PAT) gestisce solo connessioni in uscita."},
  {id:307,type:"mc",topic:"ICMP",text:"Quale messaggio ICMP viene generato da un host quando riceve un pacchetto UDP verso una porta chiusa?",options:["Time Exceeded","Destination Unreachable - Port Unreachable","Echo Reply","Redirect"],correct:1,explanation:"Port Unreachable (tipo 3, codice 3): inviato dall'host destinazione quando non c'è nessun processo in ascolto sulla porta UDP specificata nel pacchetto."},
  {id:308,type:"mc",topic:"NAT",text:"La tabella NAT viene svuotata quando:",options:["Il router si riavvia","Una sessione scade o viene chiusa","Ogni 30 secondi","Mai"],correct:1,explanation:"Le voci NAT vengono rimosse quando la sessione TCP si chiude (FIN/RST) o quando scade il timer di idle (per UDP e connessioni inattive)."},
  {id:309,type:"mc",topic:"ICMP",text:"Quale tipo ICMP è usato per il 'ping of death' (pacchetto frammentato malformato)?",options:["Tipo 3","Tipo 8 (Echo Request) malformato","Tipo 11","Tipo 0"],correct:1,explanation:"Il 'Ping of Death' usa ICMP Echo Request frammentato in modo da superare i 65535 byte al riassemblaggio — causava overflow nei vecchi OS. Ormai mitigato."},
  {id:310,type:"mc",topic:"NAT",text:"'ip nat outside source static' in Cisco IOS configura:",options:["PAT","NAT Statico Outside: traduce IP destinazione in pacchetti in ingresso","NAT Dinamico","Solo logging"],correct:1,explanation:"Outside source static: traduce l'indirizzo IP destinazione nei pacchetti in ingresso (DNAT). Usato meno comunemente di inside source static."},
  {id:311,type:"mc",topic:"ICMP",text:"traceroute su Linux usa di default quale protocollo per i probe?",options:["ICMP Echo Request","UDP verso porte alte (>30000)","TCP SYN","ICMP Timestamp"],correct:1,explanation:"traceroute Linux: usa UDP verso porte alte (33434+) per default. tracert Windows: usa ICMP Echo Request. traceroute può usare -I per ICMP o -T per TCP."},
  {id:312,type:"mc",topic:"NAT",text:"Quale comando Cisco cancella la tabella NAT?",options:["clear ip nat","no ip nat","clear ip nat translations *","reset nat table"],correct:2,explanation:"'clear ip nat translations *' cancella tutte le voci dinamiche dalla tabella NAT. Le traduzioni statiche non vengono cancellate."},
  {id:313,type:"mc",topic:"ICMP",text:"Qual è il valore TTL di default di un pacchetto inviato da macOS?",options:["64","128","255","32"],correct:0,explanation:"macOS e Linux: TTL=64. Windows: TTL=128. Cisco IOS: TTL=255. Questo permette di identificare il sistema operativo remoto dall'analisi del TTL."},
  {id:314,type:"mc",topic:"NAT",text:"In PAT, cosa rende univoca ogni sessione?",options:["Solo l'IP pubblico","L'IP pubblico + numero di porta sorgente univoco","Il MAC address","Il protocollo"],correct:1,explanation:"PAT usa la combinazione IP pubblico + porta sorgente per distinguere le sessioni di client diversi. Ogni sessione riceve una porta sorgente unica nel range 1024-65535."},
  {id:315,type:"mc",topic:"ICMP",text:"ICMP Redirect viene inviato da:",options:["L'host sorgente","Un router che conosce un percorso migliore","Il server DNS","Il destinatario finale"],correct:1,explanation:"Un router invia ICMP Redirect all'host sorgente quando sa che esiste un percorso migliore per la destinazione. L'host aggiorna la propria tabella di routing locale."},
  {id:316,type:"mc",topic:"NAT",text:"Quante sessioni PAT può gestire contemporaneamente un router (teoricamente)?",options:["255","1024","~64000 (porte disponibili)","16"],correct:2,explanation:"PAT usa le porte TCP/UDP: range 1024-65535 = ~64511 porte. Quindi può gestire teoricamente ~64000 sessioni simultanee con un solo IP pubblico."},
  {id:317,type:"mc",topic:"ICMP",text:"Quale tipo ICMP ha come codice 0 e tipo 0?",options:["Echo Request","Echo Reply","Time Exceeded","Destination Unreachable"],correct:1,explanation:"ICMP tipo 0, codice 0 = Echo Reply (risposta al ping). ICMP tipo 8, codice 0 = Echo Request (richiesta ping)."},
  {id:318,type:"tf",topic:"NAT",text:"Il NAT migliora le prestazioni di rete riducendo la latenza.",options:["Vero","Falso"],correct:1,explanation:"FALSO. Il NAT introduce latenza aggiuntiva: il router deve esaminare ogni pacchetto, cercare/aggiornare la tabella NAT e modificare gli header IP e TCP/UDP. È un overhead computazionale."},
],

"routing":[
  {id:300,type:"mc",topic:"Tabella",text:"Cosa indica 'via' nella tabella di routing di Cisco?",options:["La metrica","Il next-hop IP","L'interfaccia di uscita","Il protocollo"],correct:1,explanation:"'via X.X.X.X' indica l'indirizzo IP del next-hop router verso cui inviare i pacchetti per quella destinazione."},
  {id:301,type:"mc",topic:"Routing dinamico",text:"Quale metrica usa OSPF per scegliere il percorso migliore?",options:["Hop count","Larghezza di banda","Costo (inversamente proporzionale alla banda)","Latenza"],correct:2,explanation:"OSPF usa il 'costo': costo = banda riferimento / banda interfaccia. Interfacce più veloci → costo minore → percorso preferito."},
  {id:302,type:"mc",topic:"AS",text:"L'ASN 64512–65535 è riservato per:",options:["IANA","Uso privato/interno (non annunciato su Internet)","Università","Governi"],correct:1,explanation:"ASN 64512–65535 (16-bit) sono riservati per uso privato, come i range IP privati RFC 1918. Non devono essere annunciati su Internet pubblico."},
  {id:303,type:"mc",topic:"Bellman-Ford",text:"Quante iterazioni richiede Bellman-Ford per convergere in una rete con V nodi?",options:["1","V","V-1","V×2"],correct:2,explanation:"Bellman-Ford converge in al massimo V-1 iterazioni (V = numero di nodi). Al K-esimo passo trova tutti i percorsi di lunghezza ≤ K."},
  {id:304,type:"mc",topic:"Routing statico",text:"Una rotta statica con AD=254 è chiamata:",options:["Default route","Floating static route","Connected route","Summary route"],correct:1,explanation:"Floating static route: AD molto alta (es. 254) → usata solo come backup quando le rotte preferite (AD minore) falliscono. 'Galleggia' finché non è necessaria."},
  {id:305,type:"mc",topic:"Dijkstra",text:"Quale struttura dati migliora le prestazioni di Dijkstra?",options:["Lista ordinata","Coda di priorità (min-heap)","Stack LIFO","Tabella hash"],correct:1,explanation:"Con min-heap: O(E log V). Con array semplice: O(V²). Per reti sparse (pochi archi) il min-heap è molto più efficiente."},
  {id:306,type:"mc",topic:"IGP/EGP",text:"EIGRP è sviluppato da quale vendor?",options:["Juniper","Cisco","Nokia","Huawei"],correct:1,explanation:"EIGRP (Enhanced Interior Gateway Routing Protocol) è un protocollo proprietario Cisco. Usa l'algoritmo DUAL (Diffusing Update ALgorithm) e una metrica composita."},
  {id:307,type:"tf",topic:"Next-hop",text:"Il routing 'hop-by-hop' significa che ogni router deve conoscere l'intero percorso verso la destinazione.",options:["Vero","Falso"],correct:1,explanation:"FALSO. Hop-by-hop: ogni router conosce SOLO il prossimo salto (next-hop). La decisione è locale e distribuita — nessun router conosce l'intero percorso."},
  {id:308,type:"mc",topic:"Tabella",text:"Cosa significa il codice 'L' nella tabella di routing IOS?",options:["Link-state route","Local: indirizzo IP dell'interfaccia locale del router","Loop route","Legacy route"],correct:1,explanation:"'L' (Local): introdotto in IOS 15. Indica l'indirizzo IP dell'interfaccia locale del router stesso (host route /32). Diverso da 'C' che indica la rete della sottorete connessa."},
  {id:309,type:"mc",topic:"Routing dinamico",text:"Quale protocollo usa il 'Feasible Successor' per la convergenza rapida?",options:["RIP","OSPF","EIGRP","BGP"],correct:2,explanation:"EIGRP: il Feasible Successor è un percorso di backup pre-calcolato. Se il percorso primario (Successor) cade, EIGRP usa immediatamente il Feasible Successor senza ricalcoli → convergenza quasi istantanea."},
  {id:310,type:"mc",topic:"Tabella",text:"La 'distanza amministrativa' (AD) serve a:",options:["Calcolare la metrica","Scegliere tra rotte verso la stessa destinazione apprese da protocolli diversi","Determinare il TTL","Settare il costo OSPF"],correct:1,explanation:"Se RIP e OSPF hanno entrambi una rotta verso 10.0.0.0/8, il router usa AD per scegliere: OSPF (AD=110) è preferito a RIP (AD=120) perché ha AD minore."},
  {id:311,type:"mc",topic:"AS",text:"eBGP (external BGP) è usato tra:",options:["Router dello stesso AS","Router di AS diversi","Solo tra ISP","Solo tra router confinanti geograficamente"],correct:1,explanation:"eBGP: tra router che appartengono ad Autonomous System diversi. È la forma di BGP usata tra gli ISP per scambiarsi le tabelle di routing su Internet."},
  {id:312,type:"mc",topic:"Routing statico",text:"Qual è la AD di una rotta learned via BGP esterno in Cisco IOS?",options:["20","110","170","200"],correct:0,explanation:"BGP esterno (eBGP): AD=20. BGP interno (iBGP): AD=200. OSPF=110, RIP=120. L'eBGP è molto preferito rispetto agli IGP."},
  {id:313,type:"mc",topic:"Bellman-Ford",text:"Quale problema fondamentale ha il Distance Vector rispetto al Link-State?",options:["Usa troppa CPU","Non scala","Convergenza lenta e Count-to-Infinity","Non supporta IPv6"],correct:2,explanation:"I protocolli Distance Vector condividono solo vettori di distanza, non la topologia completa. Questo porta a convergenza lenta e Count-to-Infinity quando un link cade."},
  {id:314,type:"mc",topic:"Dijkstra",text:"In OSPF, il LSDB viene aggiornato tramite:",options:["Update periodici ogni 30s","Flooding degli LSA al cambio topologico","Richiesta esplicita ai vicini","Sincronizzazione ogni 10 minuti"],correct:1,explanation:"OSPF: quando cambia la topologia (link up/down), il router inonda (flooding) un LSA nuovo attraverso tutta l'area. Questo aggiorna il LSDB di tutti i router nell'area."},
  {id:315,type:"mc",topic:"IGP/EGP",text:"Quale protocollo usa hello/dead intervals per rilevare i guasti dei vicini?",options:["RIP","BGP","OSPF","Routing statico"],correct:2,explanation:"OSPF usa Hello packets periodici (default 10s su Ethernet). Se non si riceve un Hello per Dead Interval (default 40s = 4×Hello), il vicino è dichiarato down e la topologia viene ricalcolata."},
  {id:316,type:"mc",topic:"Routing statico",text:"Il comando 'ip route 0.0.0.0 0.0.0.0 Null0' serve a:",options:["Creare una rotta verso tutti gli host","Creare un 'black hole' per scartare traffico verso reti inesistenti","Disabilitare il routing","Creare un tunnel"],correct:1,explanation:"Route verso Null0 (black hole route): scarta i pacchetti senza inviare ICMP Unreachable. Usato per prevenire routing loop con route summarization o per bloccare traffico specifico."},
  {id:317,type:"mc",topic:"Tabella",text:"'show ip route summary' mostra:",options:["Solo le rotte OSPF","Il numero totale di rotte per tipo (C,S,R,O,B) e spazio in uso","Solo la default route","Le rotte con metrica minima"],correct:1,explanation:"'show ip route summary': statistiche della tabella di routing — numero di rotte per tipo (Connected, Static, RIP, OSPF, BGP, ecc.) e uso della memoria."},
  {id:318,type:"mc",topic:"AS",text:"BGP Route Reflector serve a:",options:["Accelerare la convergenza BGP","Evitare la regola iBGP full-mesh ridistribuendo le rotte nel medesimo AS","Filtrare le rotte esterne","Fare NAT per BGP"],correct:1,explanation:"iBGP full-mesh: ogni router iBGP deve avere sessioni con tutti gli altri (O(n²)). Route Reflector: un router centrale ridistribuisce gli update iBGP agli altri, eliminando la necessità del full-mesh."},
],

"rip":[
  {id:300,type:"mc",topic:"Metrica",text:"Se RIP riceve lo stesso prefisso da due vicini con metrica 3 e 5, quale usa?",options:["Metrica 5 (più alta)","Metrica 3 (più bassa = migliore)","Fa load balancing su entrambe","Scarta entrambe"],correct:1,explanation:"RIP sceglie la rotta con metrica più bassa (meno hop). 3 < 5, quindi si usa la rotta con metrica 3."},
  {id:301,type:"mc",topic:"Timer",text:"Il timer Holddown inizia dopo:",options:["Il timer Update","Il timer Invalid","L'avvio del router","Il timer Flush"],correct:1,explanation:"Sequenza: Update (30s periodici) → Invalid (180s senza update → rotta invalida) → Holddown (180s di attesa dopo l'Invalid) → Flush (rimozione a 240s totali)."},
  {id:302,type:"mc",topic:"Comandi",text:"Quale output NON viene mostrato da 'show ip rip database'?",options:["Reti apprese da vicini RIP","Metrica per ogni rotta","Indirizzo next-hop","Il MAC address del vicino"],correct:3,explanation:"'show ip rip database' mostra: reti, metriche, next-hop, e timer. Non mostra indirizzi MAC — quelli sono al livello L2."},
  {id:303,type:"mc",topic:"Funzionamento",text:"RIPv2 include la subnet mask negli update per supportare:",options:["Solo routing di default","VLSM e CIDR","Solo reti Classe C","Routing IPv6"],correct:1,explanation:"Includendo la subnet mask, RIPv2 è classless: può gestire VLSM (sottoreti di dimensioni diverse) e CIDR (aggregazione di rotte)."},
  {id:304,type:"mc",topic:"Confronto",text:"Rispetto a OSPF, il principale svantaggio di RIP è:",options:["Usa multicast invece di broadcast","Max 15 hop e convergenza lenta","Usa TCP invece di UDP","Non supporta IPv4"],correct:1,explanation:"I due limiti principali di RIP: 1) Max 15 hop (limite di scala). 2) Convergenza lenta (aggiornamenti periodici ogni 30s, Count-to-Infinity)."},
  {id:305,type:"mc",topic:"RIPv2",text:"L'indirizzo multicast 224.0.0.9 è usato da:",options:["OSPF","RIPv2","EIGRP","BGP"],correct:1,explanation:"RIPv2 usa 224.0.0.9 per inviare i propri update. OSPF usa 224.0.0.5 (tutti i router OSPF) e 224.0.0.6 (DR/BDR). EIGRP usa 224.0.0.10."},
  {id:306,type:"mc",topic:"Count-to-Infinity",text:"Triggered Update riduce il Count-to-Infinity perché:",options:["Aumenta la frequenza degli update periodici","Propaga immediatamente l'informazione di guasto prima del prossimo update periodico","Abbassa la metrica massima a 8","Disabilita il timer Invalid"],correct:1,explanation:"Triggered Update: al guasto, il router invia immediatamente un update con metrica 16 per la rete coinvolta. Questo previene che i vicini re-annuncino la rotta morta prima del prossimo update periodico (30s)."},
  {id:307,type:"tf",topic:"RIPv2",text:"'no auto-summary' in RIPv2 è necessario per evitare che la rete 10.1.1.0/24 venga annunciata come 10.0.0.0/8.",options:["Vero","Falso"],correct:0,explanation:"VERO. Auto-summary (default in RIPv2): tronca le rotte alla classe naturale. 10.1.1.0/24 → classe A → annunciata come 10.0.0.0/8. 'no auto-summary' mantiene la subnet mask originale."},
  {id:308,type:"mc",topic:"Funzionamento",text:"RIP può fare load balancing su percorsi con:",options:["Qualsiasi metrica diversa","Stessa metrica (ECMP - Equal Cost Multi-Path)","Metrica che differisce al massimo di 1","Solo su 2 percorsi"],correct:1,explanation:"RIP supporta ECMP (Equal Cost Multi-Path): se due percorsi verso la stessa destinazione hanno la stessa metrica, il router distribuisce il traffico su entrambi (fino a 4 percorsi di default in Cisco IOS)."},
  {id:309,type:"mc",topic:"Timer",text:"Perché il Holddown Timer previene i routing loop?",options:["Blocca tutti gli update","Impedisce di accettare update con metrica peggiore durante il periodo di instabilità","Aumenta la metrica","Disabilita Split Horizon"],correct:1,explanation:"Durante l'Holddown, il router ignora update con metrica ≥ a quella invalida (16). Questo impedisce che router confusi ri-annuncino la rotta morta con metrica 'migliore', causando loop."},
  {id:310,type:"mc",topic:"Comandi",text:"'debug ip rip' deve essere disabilitato con:",options:["stop debug","no debug ip rip / undebug all","disable debug","clear debug rip"],correct:1,explanation:"'no debug ip rip' o 'undebug all' (abbreviabile 'u all') disabilitano il debug. Lasciare il debug attivo su router di produzione causa overhead CPU significativo."},
  {id:311,type:"mc",topic:"RIPv1 vs v2",text:"RIPv1 invia update in broadcast perché:",options:["Il multicast non esisteva quando RIPv1 fu definito","È più sicuro del multicast","Raggiunge più dispositivi","È richiesto dallo standard IP"],correct:0,explanation:"RIPv1 fu standardizzato nel 1988 (RFC 1058), prima che il multicast fosse ampiamente implementato. RIPv2 (1994, RFC 1723) ha aggiunto il supporto multicast."},
  {id:312,type:"mc",topic:"Metrica",text:"In RIP, un router che annuncia una rete direttamente connessa la annuncia con metrica:",options:["0","1","2","Dipende dalla banda"],correct:1,explanation:"Le reti direttamente connesse vengono annunciate con metrica 1 (non 0). I vicini le riceveranno con metrica 1+1=2."},
  {id:313,type:"mc",topic:"Funzionamento",text:"Ogni quanto tempo RIP invia i propri update ai vicini?",options:["Ogni 10s","Ogni 30s","Ogni 90s","Solo al cambio"],correct:1,explanation:"RIP Update Timer: 30 secondi. Gli update periodici vengono inviati ai vicini anche in assenza di cambiamenti nella topologia. Questo è uno degli svantaggi di RIP rispetto a OSPF."},
  {id:314,type:"tf",topic:"RIPv2",text:"RIPv2 può autenticare i messaggi di routing per prevenire rogue router.",options:["Vero","Falso"],correct:0,explanation:"VERO. RIPv2 supporta autenticazione: plaintext (password in chiaro, poco sicuro) o MD5 (hash della password). Previene che router non autorizzati iniettino rotte false nella rete."},
  {id:315,type:"mc",topic:"Split Horizon",text:"Split Horizon si applica in quale direzione?",options:["Verso la destinazione","Verso la sorgente da cui è stata appresa la rotta","Verso tutti i vicini","Verso i router non vicini"],correct:1,explanation:"Split Horizon: non ri-annunciare una rotta verso il vicino da cui l'hai appresa. Se R1 ha imparato 'rete X' da R2, non annuncia 'rete X' a R2."},
  {id:316,type:"mc",topic:"Comandi",text:"Cosa mostra 'show ip protocols' per RIP?",options:["Solo la versione","Versione, reti, vicini, timer, AD","Solo le rotte","Il MAC dei vicini"],correct:1,explanation:"'show ip protocols' per RIP mostra: versione (1/2), reti annunciate (network), vicini rilevati, timer (update/invalid/holddown/flush), distanza amministrativa (120)."},
],

"ospf-bgp":[
  {id:300,type:"mc",topic:"OSPF",text:"Cosa è il 'Dead Interval' in OSPF?",options:["Il tempo prima che il router venga spento","Il tempo senza Hello prima di dichiarare un vicino down","Il costo massimo di una rotta","Il timer di aggiornamento LSA"],correct:1,explanation:"Dead Interval (default 40s = 4×Hello): se non si riceve nessun Hello da un vicino per questo periodo, il vicino viene dichiarato down e i LSA vengono aggiornati."},
  {id:301,type:"mc",topic:"OSPF",text:"Quale tipo di rete OSPF NON elegge un DR/BDR?",options:["Ethernet","Token Ring","Rete Point-to-Point (PPP, HDL)","NBMA"],correct:2,explanation:"Su reti Point-to-Point (2 router collegati direttamente), non si elegge DR/BDR — non c'è necessità di ridurre le adiacenze."},
  {id:302,type:"mc",topic:"BGP",text:"Quale attributo BGP viene usato per prevenire i routing loop?",options:["LOCAL_PREF","NEXT_HOP","AS_PATH","MED"],correct:2,explanation:"AS_PATH: contiene la lista degli AS attraversati. Se un router riceve un annuncio con il proprio ASN già nel percorso, lo scarta — prevenendo i loop di routing."},
  {id:303,type:"mc",topic:"OSPF",text:"Cosa è il 'virtual link' in OSPF?",options:["Un tunnel IPsec","Un collegamento logico tra un'area non connessa all'Area 0 e il backbone","Un link wireless","Un VPN link"],correct:1,explanation:"Virtual Link: permette a un'area OSPF non direttamente connessa all'Area 0 di raggiungere il backbone attraverso un'area di transito. Soluzione per topologie non gerarchiche."},
  {id:304,type:"mc",topic:"BGP",text:"Quale AS numero è usato in iBGP?",options:["Sempre 65535","Lo stesso ASN di tutti i router nell'AS","ASN diverso per ogni router","Non si usa ASN in iBGP"],correct:1,explanation:"In iBGP (Internal BGP), tutti i router appartenenti allo stesso AS usano lo stesso numero AS. Le sessioni iBGP sono tra router dello stesso AS."},
  {id:305,type:"mc",topic:"OSPF",text:"Il BDR (Backup Designated Router) in OSPF serve a:",options:["Fare il backup del LSDB","Subentrare al DR in caso di fallimento","Fare load balancing col DR","Gestire le aree satellite"],correct:1,explanation:"BDR: monitorizza il DR e prende il suo posto immediatamente in caso di fallimento, senza dover attendere l'elezione di un nuovo DR. Riduce i tempi di convergenza."},
  {id:306,type:"mc",topic:"BGP",text:"BGP sceglie il percorso migliore basandosi su (prima tra le seguenti):",options:["Metrica più bassa","WEIGHT più alto (Cisco specifico)","Hop count più basso","Costo della banda"],correct:1,explanation:"L'algoritmo di selezione BGP valuta attributi nell'ordine: WEIGHT (Cisco) → LOCAL_PREF → Locally originated → AS_PATH (più breve) → ORIGIN → MED → eBGP over iBGP → IGP metric → ..."},
  {id:307,type:"mc",topic:"OSPF",text:"Quale LSA descrive le rotte verso destinazioni esterne all'area OSPF?",options:["LSA Tipo 1","LSA Tipo 2","LSA Tipo 3","LSA Tipo 5"],correct:3,explanation:"LSA Tipo 5 (AS External LSA): generato dall'ASBR per annunciare rotte esterne all'AS OSPF (es. rotte redistribuite da BGP o rotte statiche). Inondato in tutta la rete OSPF."},
  {id:308,type:"mc",topic:"OSPF",text:"Cos'è il router-id di OSPF e come viene scelto?",options:["Il hostname del router","L'IP più alto tra loopback attive, poi IP più alto tra interfacce fisiche","Il primo IP configurato","Il MAC address"],correct:1,explanation:"Router-ID OSPF (32-bit): 1) IP più alto tra le interfacce loopback attive. 2) Se non ci sono loopback, IP più alto tra le interfacce fisiche attive. 3) Può essere configurato manualmente: 'router-id X.X.X.X'."},
  {id:309,type:"mc",topic:"BGP",text:"Cosa è il 'BGP community'?",options:["Un gruppo di AS con stesso policy","Un tag (32-bit) applicato alle rotte BGP per raggruppare e filtrare","Un tipo di AS","Un protocollo di sicurezza BGP"],correct:1,explanation:"BGP Community: attributo opzionale (32-bit) usato per taggare le rotte e applicare policy. Es. community 'no-export' → la rotta non viene annunciata ad eBGP peer. Permette policy di routing scalabili."},
  {id:310,type:"mc",topic:"OSPF",text:"In OSPF, quale router genera i LSA Tipo 3?",options:["Internal Router","ASBR","ABR (Area Border Router)","DR"],correct:2,explanation:"ABR genera LSA Tipo 3 (Summary LSA): riassume le rotte di un'area verso l'Area 0 e viceversa. Permette la comunicazione inter-area."},
  {id:311,type:"mc",topic:"BGP",text:"Qual è la differenza tra 'hard reset' e 'soft reset' BGP?",options:["Hard reset è più veloce","Hard reset riabbatte la sessione TCP, soft reset usa route refresh senza resettare","Soft reset è solo per iBGP","Non c'è differenza"],correct:1,explanation:"Hard reset: chiude la sessione TCP e la riapre (interruzione del servizio). Soft reset: usa Route Refresh (RFC 2918) per richiedere il re-annuncio delle rotte senza abbattere la sessione."},
  {id:312,type:"mc",topic:"OSPF",text:"OSPF usa quale algoritmo per il calcolo dei percorsi?",options:["Bellman-Ford","Floyd-Warshall","Dijkstra (SPF)","A*"],correct:2,explanation:"OSPF usa l'algoritmo SPF (Shortest Path First) di Dijkstra. Ogni router esegue SPF sul proprio LSDB per calcolare l'albero dei percorsi minimi."},
  {id:313,type:"mc",topic:"BGP",text:"Il numero di sessioni TCP richieste per una rete iBGP full-mesh con N router è:",options:["N","N-1","N×(N-1)/2","N²"],correct:2,explanation:"Full-mesh iBGP: ogni router deve avere una sessione TCP con tutti gli altri. N router → N×(N-1)/2 sessioni. Con 10 router: 45 sessioni. Soluzione: Route Reflector o Confederazioni."},
  {id:314,type:"mc",topic:"OSPF",text:"Cosa causa un 'LSA flooding storm' in OSPF?",options:["Troppi router nell'area","Un link instabile che flappa continuamente (link flapping)","Router con costo troppo alto","L'assenza di DR"],correct:1,explanation:"Link flapping: un link che va su e giù ripetutamente genera continuamente nuovi LSA inondati nella rete. Causa overhead significativo. Soluzione: dampening, timer BFD, manutenzione hardware."},
  {id:315,type:"mc",topic:"BGP",text:"MED (Multi-Exit Discriminator) in BGP serve a:",options:["Identificare il router BGP","Indicare al vicino eBGP quale exit preferire per lo stesso AS","Calcolare il costo del link","Autenticare BGP peer"],correct:1,explanation:"MED: attributo inviato all'AS vicino per indicare la preferenza di entrata. Es. AS1 annuncia la stessa rete con MED=100 via un router e MED=200 via un altro → l'AS vicino preferisce MED=100 (valore minore)."},
  {id:316,type:"mc",topic:"OSPF",text:"Quale vantaggio ha la struttura ad aree di OSPF?",options:["Elimina la necessità del DR","Riduce la dimensione del LSDB e isola i cambiamenti topologici","Aumenta la metrica","Permette loop di routing"],correct:1,explanation:"Struttura ad aree: ogni area mantiene il proprio LSDB ridotto. Un cambiamento topologico in Area 1 non inonda LSA in Area 2. Questo riduce overhead e migliora la scalabilità."},
],

"crittografia":[
  {id:300,type:"mc",topic:"Simmetrica",text:"Quale algoritmo di cifratura simmetrica è il più veloce per lo streaming?",options:["AES-ECB","AES-CBC","ChaCha20","3DES"],correct:2,explanation:"ChaCha20 è un cifrario stream particolarmente veloce su dispositivi senza accelerazione hardware AES (es. smartphone economici). Usato in TLS 1.3 e WireGuard VPN."},
  {id:301,type:"mc",topic:"Asimmetrica",text:"ECC (Elliptic Curve Cryptography) offre rispetto a RSA:",options:["Meno sicurezza","Stessa sicurezza con chiavi più corte","Più sicurezza con chiavi più lunghe","Nessuna differenza"],correct:1,explanation:"ECC: una chiave ECDSA di 256 bit = sicurezza equivalente a RSA 3072 bit. Meno dati da trasmettere e computazione più veloce, ideale per dispositivi mobili e IoT."},
  {id:302,type:"mc",topic:"Obiettivi",text:"La crittografia end-to-end garantisce che:",options:["Solo i provider possono leggere i dati","Solo mittente e destinatario possono leggere i dati","I dati sono protetti solo in transito","I dati sono cifrati solo sui server"],correct:1,explanation:"End-to-end encryption: il messaggio è cifrato dal dispositivo del mittente e decifrato solo dal dispositivo del destinatario. Neanche il provider del servizio (intermediario) può leggerlo."},
  {id:303,type:"mc",topic:"AES",text:"AES-GCM è considerato AEAD perché:",options:["Usa due chiavi","Fornisce sia cifratura che autenticazione integrata","È più veloce di AES-CBC","Usa padding variabile"],correct:1,explanation:"AEAD (Authenticated Encryption with Associated Data): AES-GCM combina cifratura (AES-CTR) e autenticazione (GHASH) in un unico algoritmo. Garantisce confidenzialità E integrità senza un MAC separato."},
  {id:304,type:"mc",topic:"Simmetrica",text:"Quale algoritmo usa chiavi di sessione effimere per garantire la Perfect Forward Secrecy?",options:["RSA con chiavi fisse","ECDHE (Elliptic Curve DH Ephemeral)","AES-256","3DES"],correct:1,explanation:"ECDHE genera nuove chiavi DH per ogni sessione. Anche se la chiave privata a lungo termine viene compromessa, le sessioni passate rimangono protette perché le chiavi effimere non sono state salvate."},
  {id:305,type:"mc",topic:"Asimmetrica",text:"Dove NON si usa la crittografia asimmetrica?",options:["Firma digitale","Scambio di chiavi","Cifratura di grandi file (performance inadeguata)","Certificati digitali"],correct:2,explanation:"La crittografia asimmetrica è ~1000x più lenta della simmetrica. Non si usa per cifrare grandi quantità di dati (es. file, stream video). Si usa per firma, scambio chiavi e certificati."},
  {id:306,type:"mc",topic:"Obiettivi",text:"Quale proprietà garantisce che solo il destinatario autorizzato possa leggere il messaggio?",options:["Integrità","Autenticazione","Confidenzialità","Non ripudio"],correct:2,explanation:"Confidenzialità: il messaggio è leggibile solo dal destinatario autorizzato. Si ottiene cifrando il messaggio con la chiave pubblica del destinatario (asimmetrica) o con una chiave condivisa (simmetrica)."},
  {id:307,type:"mc",topic:"Sistema ibrido",text:"In SSH, quale meccanismo di scambio chiavi viene usato per stabilire la chiave di sessione?",options:["Solo RSA","Diffie-Hellman o ECDH","Solo AES","Solo password"],correct:1,explanation:"SSH usa DH o ECDH per lo scambio di chiavi di sessione, garantendo Perfect Forward Secrecy. Le chiavi di sessione sono poi usate per cifrare il traffico con AES."},
  {id:308,type:"mc",topic:"DES",text:"Quale è la dimensione dei blocchi DES?",options:["32 bit","56 bit","64 bit","128 bit"],correct:2,explanation:"DES: chiave 56 bit, blocchi 64 bit. AES: chiave 128/192/256 bit, blocchi 128 bit."},
  {id:309,type:"mc",topic:"AES",text:"Quale modalità operativa di AES non dovrebbe mai essere usata per cifrare più di un blocco?",options:["AES-GCM","AES-CBC","AES-ECB","AES-CTR"],correct:2,explanation:"AES-ECB (Electronic Codebook): blocchi identici di plaintext producono blocchi identici di ciphertext. Un attaccante può vedere i pattern anche senza decifrare — famosa vulnerabilità visualizzata con la 'ECB penguin'."},
  {id:310,type:"mc",topic:"Asimmetrica",text:"La firma digitale RSA usa l'hash del messaggio perché:",options:["L'hash è più sicuro del messaggio","RSA può firmare solo quantità fisse di dati e l'hash ha dimensione fissa","Per velocità — hash è piccolo","Per obblighi normativi"],correct:1,explanation:"RSA può operare solo su quantità di dati ≤ alla dimensione della chiave. Firmando l'hash (es. 256 bit per SHA-256) invece del messaggio intero, si risolve il limite di dimensione e si migliora le prestazioni."},
  {id:311,type:"mc",topic:"Simmetrica",text:"Cosa si intende per 'key wrapping'?",options:["Rinnovo della chiave","Cifrare una chiave simmetrica con un'altra chiave (es. la chiave pubblica del destinatario)","Dividere una chiave in parti","Ruotare le chiavi"],correct:1,explanation:"Key wrapping: cifrare una chiave simmetrica con un'altra chiave (es. chiave pubblica RSA o chiave AES di key-encryption-key). Permette di trasmettere chiavi simmetriche in sicurezza. Usato in PGP e in standard come RFC 3394."},
  {id:312,type:"mc",topic:"Obiettivi",text:"Il principio di Kerckhoffs afferma che:",options:["La chiave deve essere segreta ma l'algoritmo può essere pubblico","L'algoritmo deve essere segreto","Nessun algoritmo è sicuro","La lunghezza della chiave non importa"],correct:0,explanation:"Principio di Kerckhoffs (1883): la sicurezza di un sistema crittografico deve dipendere SOLO dalla segretezza della chiave, non dell'algoritmo. Gli algoritmi moderni (AES, RSA) sono pubblici e analizzati dalla comunità."},
],

"diffie-hellman":[
  {id:300,type:"mc",topic:"DH",text:"Nel protocollo DH, cosa viene scambiato pubblicamente?",options:["Le chiavi private","I valori intermedi g^a mod p e g^b mod p","La chiave simmetrica finale","Le password"],correct:1,explanation:"Alice calcola g^a mod p, Bob calcola g^b mod p. Si scambiano questi valori pubblicamente. Alice calcola (g^b)^a = g^(ab) e Bob calcola (g^a)^b = g^(ab) → stessa chiave condivisa."},
  {id:301,type:"mc",topic:"Hash",text:"Cosa garantisce la 'resistenza alle pre-immagini' di una funzione hash?",options:["Dato h(x), è impossibile trovare x","Due input diversi non possono avere lo stesso hash","L'hash è sempre diverso dall'input","L'hash è invertibile"],correct:0,explanation:"Resistenza alle pre-immagini (one-way): dato l'hash h(x), è computazionalmente impossibile trovare x. Fondamentale per il password hashing — anche se il database degli hash è rubato, le password originali non si recuperano."},
  {id:302,type:"mc",topic:"Firma",text:"Quale standard definisce il formato delle firme digitali basate su RSA?",options:["RFC 1918","PKCS#1 / RFC 8017","RFC 2328","IEEE 802.1X"],correct:1,explanation:"PKCS#1 (RSA Cryptography Standard, RFC 8017): definisce le primitive crittografiche RSA incluse le firme digitali (RSASSA-PKCS1-v1_5, RSASSA-PSS)."},
  {id:303,type:"mc",topic:"MAC",text:"La differenza tra integrità e autenticazione nel MAC è:",options:["Sono la stessa cosa","Integrità = dato non alterato; Autenticazione = chi ha inviato. Il MAC garantisce ENTRAMBE","Solo l'autenticazione è garantita","Solo l'integrità è garantita"],correct:1,explanation:"MAC garantisce entrambe: integrità (il dato non è stato modificato) e autenticazione (solo chi ha la chiave condivisa può produrre un MAC valido). Un semplice hash garantisce solo l'integrità."},
  {id:304,type:"mc",topic:"MFA",text:"Quale tipo di OTP è più sicuro contro gli attacchi di intercettazione?",options:["OTP via SMS","TOTP via app","HOTP (counter-based)","Email OTP"],correct:1,explanation:"TOTP via app: il codice viene generato localmente, senza trasmetterlo sulla rete mobile (non intercettabile via SIM swapping o SS7 attack). SMS e email OTP viaggiano su canali meno sicuri."},
  {id:305,type:"mc",topic:"DH",text:"ECDH usa quale struttura matematica?",options:["Numeri primi grandi","Curve ellittiche su campi finiti","Funzioni hash","Reticoli (lattice)"],correct:1,explanation:"ECDH (Elliptic Curve DH): sostituisce il tradizionale DH basato su gruppi moltiplicativi (numeri interi modulo un primo) con curve ellittiche su campi finiti GF(p) o GF(2^m). Offre sicurezza equivalente con chiavi molto più corte."},
  {id:306,type:"mc",topic:"Hash",text:"SHA-256 produce un output di quanto?",options:["128 bit","160 bit","256 bit","512 bit"],correct:2,explanation:"SHA-256 (Secure Hash Algorithm 256-bit): produce sempre un digest di 256 bit = 32 byte = 64 caratteri esadecimali, indipendentemente dalla dimensione dell'input."},
  {id:307,type:"mc",topic:"Firma",text:"Quale algoritmo di firma digitale usa curve ellittiche?",options:["RSA","DSA","ECDSA","MD5withRSA"],correct:2,explanation:"ECDSA (Elliptic Curve Digital Signature Algorithm): versione delle firme digitali su curve ellittiche. Chiavi più corte di RSA per la stessa sicurezza. Usato in Bitcoin, TLS 1.3, certificati moderni."},
  {id:308,type:"mc",topic:"HMAC",text:"In quale protocollo di rete viene usato HMAC per autenticare i messaggi?",options:["HTTP","FTP","IPsec / TLS","Telnet"],correct:2,explanation:"HMAC è usato in: IPsec (AH e ESP per autenticazione del payload), TLS (record MAC per ogni blocco dati), SSH (MAC di ogni pacchetto), API REST (HMAC-SHA256 per firmare le richieste)."},
  {id:309,type:"mc",topic:"MFA",text:"Quale fattore MFA è più difficile da duplicare da parte di un attaccante fisico?",options:["Password","Token software (TOTP)","Chiave hardware U2F","SMS OTP"],correct:2,explanation:"Chiave hardware U2F/FIDO2 (es. YubiKey): dispositivo fisico che firma crittograficamente con una chiave privata non estraibile. È impossibile duplicare la chiave senza accesso fisico al dispositivo."},
  {id:310,type:"mc",topic:"DH",text:"Perché DH da solo non garantisce autenticazione?",options:["Perché è troppo lento","Perché non verifica l'identità delle parti — vulnerabile a MITM","Perché usa chiavi troppo corte","Perché non supporta IPv6"],correct:1,explanation:"DH senza autenticazione: un attaccante può fare MITM intercettando lo scambio e fingendo di essere l'altra parte per entrambi i lati. In IPsec e TLS, DH è combinato con certificati o PSK per l'autenticazione."},
  {id:311,type:"mc",topic:"Hash",text:"Il 'birthday attack' sfrutta quale proprietà degli hash?",options:["La one-way property","La resistenza alle collisioni (trovare due input con lo stesso hash)","L'effetto valanga","Il determinismo"],correct:1,explanation:"Birthday attack: basato sul paradosso del compleanno — trovare una collisione (due input diversi con stesso hash) richiede solo ~2^(n/2) operazioni invece di 2^n. Per SHA-256: ~2^128 invece di 2^256."},
],

"pki":[
  {id:300,type:"mc",topic:"CA",text:"Cosa è il 'certificate transparency'?",options:["Un tipo di certificato EV","Un log pubblico di tutti i certificati emessi dalle CA, consultabile da chiunque","Un protocollo per OCSP","Un tipo di CRL"],correct:1,explanation:"Certificate Transparency (CT): log pubblici append-only dove le CA devono pubblicare i certificati emessi. Permette di rilevare certificati emessi fraudolentemente. Obbligatorio per certificati TLS pubblici da Chrome."},
  {id:301,type:"mc",topic:"X.509",text:"Quale campo di un certificato identifica il numero unico del certificato emesso da quella CA?",options:["Subject","Serial Number","Signature Algorithm","Public Key"],correct:1,explanation:"Serial Number: numero univoco assegnato dalla CA a ogni certificato che emette. Usato nelle CRL per identificare i certificati revocati."},
  {id:302,type:"mc",topic:"PKI",text:"Cosa succede a un certificato SSL quando la CA intermediaria viene revocata?",options:["Rimane valido","Viene invalidato anche il certificato foglia emesso da quella CA","Diventa EV automaticamente","Scade immediatamente"],correct:1,explanation:"Se una CA intermediaria viene revocata, tutti i certificati da lei emessi diventano non fidati. I browser mostrano avvisi di sicurezza per tutti i siti con certificati di quella CA intermediaria."},
  {id:303,type:"mc",topic:"CA",text:"Perché la Root CA viene tenuta offline?",options:["Per risparmiare energia","Per massimizzare la sicurezza: se non è connessa non può essere attaccata da remoto","Per compatibilità con sistemi legacy","Non viene tenuta offline"],correct:1,explanation:"Root CA offline: la chiave privata della Root CA è il bene più prezioso della PKI. Tenerla su un sistema air-gapped (fisicamente disconnesso da ogni rete) la protegge da attacchi remoti."},
  {id:304,type:"mc",topic:"Revoca",text:"Cosa è una 'short-lived certificate' come alternativa alla revoca?",options:["Certificato DV","Certificato con validità molto breve (ore/giorni) che non richiede revoca","Certificato autofirmato","Certificato OV"],correct:1,explanation:"Short-lived certificates: scadono così presto che non vale la pena revocarli. Invece di gestire CRL/OCSP, si emettono certificati che durano ore o giorni. Approccio usato da alcune CA moderne e in ambienti DevOps."},
  {id:305,type:"mc",topic:"PKI",text:"Cosa è il 'Web of Trust' (usato in PGP)?",options:["Una PKI gerarchica con Root CA","Una rete di fiducia peer-to-peer dove gli utenti firmano i certificati altrui","Un protocollo VPN","Un tipo di firewall"],correct:1,explanation:"Web of Trust (PGP/GPG): alternativa alla PKI gerarchica. Non c'è una CA centrale — gli utenti firmano le chiavi altrui, creando una rete di fiducia distribuita. Più flessibile ma più difficile da gestire."},
  {id:306,type:"mc",topic:"X.509",text:"Quale estensione X.509 indica se un certificato può essere usato come CA?",options:["Subject Alternative Name","Basic Constraints (CA:TRUE)","Key Usage","Extended Key Usage"],correct:1,explanation:"Basic Constraints: se CA:TRUE, il certificato può essere usato per firmare altri certificati (è una CA). I certificati foglia (end-entity) hanno CA:FALSE o non hanno questa estensione."},
  {id:307,type:"mc",topic:"CA",text:"Cosa è una 'cross-certificate' in PKI?",options:["Un certificato valido su tutti i browser","Un certificato emesso da CA_A per CA_B, permettendo ai client che si fidano di A di fidarsi anche di B","Un certificato wildcard","Un certificato autofirmato"],correct:1,explanation:"Cross-certificate: permette di stabilire fiducia tra due PKI separate. CA_A firma un certificato per CA_B → i client che si fidano di A ora si fidano anche dei certificati emessi da B."},
  {id:308,type:"mc",topic:"Tipi",text:"Un certificato wildcard *.example.com copre:",options:["Tutti i sottodomini di secondo livello: *.*.example.com","Solo www.example.com","Tutti i sottodomini di primo livello: mail.example.com, api.example.com","Anche example.com senza sottodominio"],correct:2,explanation:"Wildcard *.example.com: copre tutti i sottodomini diretti (mail.example.com, api.example.com) ma NON i sotto-sottodomini (sub.mail.example.com) né il dominio radice (example.com)."},
  {id:309,type:"mc",topic:"PKI",text:"Cosa è il 'Key Escrow'?",options:["La perdita delle chiavi private","Il deposito delle chiavi private presso un terzo (es. per uso legale)","La rotazione delle chiavi","Il backup dei certificati"],correct:1,explanation:"Key Escrow: le chiavi private vengono depositate presso un ente terzo di fiducia (es. governo, ufficio legale). Permette il recupero in caso di morte del titolare o per accesso legale autorizzato. Controverso per la privacy."},
  {id:310,type:"mc",topic:"Revoca",text:"Quale è lo svantaggio principale della CRL?",options:["È troppo sicura","Può essere obsoleta (aggiornata periodicamente, non in tempo reale)","Non funziona con IPv6","Usa troppa banda"],correct:1,explanation:"CRL: lista scaricata periodicamente (ogni ore/giorni). Un certificato revocato oggi potrebbe non apparire nella CRL fino al prossimo aggiornamento → finestra di vulnerabilità. OCSP risolve questo con query in tempo reale."},
  {id:311,type:"mc",topic:"X.509",text:"Il campo 'Issuer' in un certificato X.509 identifica:",options:["Il titolare del certificato","La CA che ha emesso e firmato il certificato","La data di scadenza","Il tipo di chiave"],correct:1,explanation:"Issuer: identifica la CA che ha emesso il certificato. Contiene il Distinguished Name (DN) della CA: CN, O, OU, C. Il client usa l'Issuer per trovare il certificato della CA e verificare la firma."},
  {id:312,type:"mc",topic:"CA",text:"Quante Root CA pre-installate ha tipicamente un browser moderno?",options:["5-10","50-150 o più","1","500+"],correct:1,explanation:"I browser moderni pre-installano 50-150+ Root CA da diversi paesi e organizzazioni. Ogni Root CA nel trust store può emettere certificati validi per qualsiasi dominio — un motivo per cui la fiducia nelle CA è critica."},
  {id:313,type:"mc",topic:"PKI",text:"Cosa è un HSM (Hardware Security Module)?",options:["Un tipo di firewall","Dispositivo hardware dedicato per operazioni crittografiche e protezione delle chiavi","Un protocollo di backup","Un tipo di certificato"],correct:1,explanation:"HSM: dispositivo hardware tamper-resistant che esegue operazioni crittografiche (generazione chiavi, firma, decifratura) e protegge le chiavi private. Usato dalle CA per proteggere la chiave privata della Root CA."},
],

"ssl-tls":[
  {id:300,type:"mc",topic:"Versioni",text:"Quale cipher suite è raccomandata in TLS 1.3?",options:["TLS_RSA_WITH_AES_128_CBC_SHA","TLS_AES_256_GCM_SHA384","TLS_DES_40_CBC_SHA","TLS_NULL_WITH_NULL_NULL"],correct:1,explanation:"TLS 1.3 raccomanda: TLS_AES_128_GCM_SHA256, TLS_AES_256_GCM_SHA384, TLS_CHACHA20_POLY1305_SHA256. Le vecchie cipher suite con RSA key exchange, CBC, RC4 sono state rimosse."},
  {id:301,type:"mc",topic:"Handshake",text:"0-RTT in TLS 1.3 permette di:",options:["Completare l'handshake senza nessun round trip","Inviare dati applicativi nel primo messaggio (pre-shared session ticket)","Eliminare i certificati","Usare chiavi statiche"],correct:1,explanation:"0-RTT (zero round-trip resumption): un client che ha già una sessione TLS 1.3 con il server può inviare dati nel primo messaggio usando un pre-shared key (PST). Più veloce ma senza Perfect Forward Secrecy per quei dati."},
  {id:302,type:"mc",topic:"Sistema ibrido",text:"In TLS 1.3, RSA key exchange è stato rimosso perché:",options:["È troppo lento","Non fornisce Perfect Forward Secrecy","Non supporta IPv6","È incompatibile con SHA-256"],correct:1,explanation:"RSA key exchange (RSA key transport): il pre-master secret è cifrato con la chiave pubblica del server. Se la chiave privata del server è compromessa in futuro, tutte le sessioni passate sono decifrabili. Non ha PFS."},
  {id:303,type:"mc",topic:"Chiavi",text:"Le 4 chiavi TLS vengono derivate dal master secret usando:",options:["MD5","Una funzione di derivazione delle chiavi (PRF/HKDF)","DES","SHA-1 semplice"],correct:1,explanation:"TLS 1.2: usa PRF (Pseudo-Random Function) basata su HMAC. TLS 1.3: usa HKDF (HMAC-based Key Derivation Function, RFC 5869) per derivare le chiavi di sessione dal master secret."},
  {id:304,type:"mc",topic:"Versioni",text:"Quale versione TLS è stata deprecata da RFC 8996?",options:["TLS 1.3","TLS 1.2","TLS 1.0 e TLS 1.1","Tutte le versioni"],correct:2,explanation:"RFC 8996 (2021) depreca TLS 1.0 e TLS 1.1. I browser moderni non accettano più questi protocolli. TLS 1.2 è ancora in uso ma TLS 1.3 è il nuovo standard."},
  {id:305,type:"mc",topic:"HTTPS",text:"HSTS (HTTP Strict Transport Security) serve a prevenire:",options:["Attacchi XSS","Downgrade attack da HTTPS a HTTP","SQL injection","Certificate spoofing"],correct:1,explanation:"HSTS: dopo la prima visita HTTPS, il browser ricorda che quel sito usa sempre HTTPS. Ignora i redirect HTTP → HTTPS e rifiuta connessioni non sicure, prevenendo attacchi di downgrade e SSL stripping."},
  {id:306,type:"mc",topic:"Handshake",text:"Il 'Finished' message in TLS verifica che:",options:["Il certificato è valido","L'intero handshake non è stato manomesso (hash di tutti i messaggi precedenti)","La connessione è cifrata","Il server è raggiungibile"],correct:1,explanation:"Finished: MAC/hash di tutti i messaggi dell'handshake fino a quel punto, cifrato con le nuove chiavi di sessione. Entrambi i lati lo verificano → garantisce che l'handshake non sia stato modificato da un MITM."},
  {id:307,type:"mc",topic:"Sistema ibrido",text:"Quale meccanismo in TLS 1.3 garantisce obbligatoriamente la PFS?",options:["RSA","DHE o ECDHE per lo scambio di chiavi","AES-256","SHA-384"],correct:1,explanation:"TLS 1.3 usa OBBLIGATORIAMENTE DHE o ECDHE per lo scambio di chiavi, garantendo PFS. RSA key exchange (senza PFS) è stato rimosso da TLS 1.3."},
  {id:308,type:"mc",topic:"Record Layer",text:"Il tipo di record TLS che porta i dati applicativi è:",options:["Alert (21)","Handshake (22)","Application Data (23)","Change Cipher Spec (20)"],correct:2,explanation:"Tipi di record TLS: 20=ChangeCipherSpec, 21=Alert, 22=Handshake, 23=ApplicationData. I dati HTTP, FTP, ecc. viaggiano nel tipo 23 (Application Data)."},
  {id:309,type:"mc",topic:"Versioni",text:"TLS è trasparente alle applicazioni, il che significa:",options:["Le applicazioni devono essere riscritte","HTTP, FTP, SMTP possono usare TLS senza modifiche al protocollo applicativo","TLS cambia automaticamente il protocollo","TLS funziona solo con HTTP"],correct:1,explanation:"TLS è trasparente: si inserisce tra TCP e il protocollo applicativo senza che le applicazioni debbano essere modificate. HTTPS = HTTP sopra TLS. SMTPS = SMTP sopra TLS. IMAPS = IMAP sopra TLS."},
  {id:310,type:"mc",topic:"Handshake",text:"Cosa contiene il messaggio 'Server Hello Done' in TLS 1.2?",options:["La chiave simmetrica","Indica che il server ha finito di inviare le sue proposte iniziali","Il certificato del server","Il pre-master secret"],correct:1,explanation:"Server Hello Done: messaggio vuoto che segnala al client che il server ha terminato l'invio delle sue proposte (Hello + Certificato + eventuale Certificate Request). Il client ora elabora le informazioni ricevute."},
  {id:311,type:"mc",topic:"HTTPS",text:"Il flag 'Secure' in un cookie HTTPS indica:",options:["Il cookie è cifrato","Il cookie viene trasmesso SOLO su connessioni HTTPS","Il cookie è accessibile via JavaScript","Il cookie ha una firma digitale"],correct:1,explanation:"Flag Secure nei cookie: il browser invia il cookie SOLO su connessioni HTTPS. Se il sito passa ad HTTP (es. per un redirect), il cookie non viene inviato, proteggendo i dati sensibili (es. session token)."},
  {id:312,type:"mc",topic:"Chiavi",text:"In TLS, quante chiavi di sessione vengono derivate dal master secret?",options:["1","2","4","8"],correct:2,explanation:"4 chiavi: client_write_key (cifratura C→S), server_write_key (cifratura S→C), client_write_MAC_key (MAC C→S), server_write_MAC_key (MAC S→C). Separazione per direzione e funzione."},
]
};
